import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;

public class XSSSafeServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("userInput");

        // Validate user input to prevent script injection
        if (!ESAPI.validator().isValidInput("userInput", userInput, "SafeString", 100, false)) {
            // Handle invalid input (e.g., return an error message)
            return;
        }

        // Encode user input before embedding into HTML response
        String safeUserInput = ESAPI.encoder().encodeForHTML(userInput);

        String htmlResponse = "<html><body><h1>Welcome " + safeUserInput + "</h1></body></html>";

        PrintWriter out = response.getWriter();
        out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
